SELECT bs."in.comstock_building_type" AS comstock_building_type, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.electricity.total.energy_consumption..kwh" * bs.weight) AS "electricity.total.energy_consumption..kwh__baseline", sum(up."out.electricity.total.energy_consumption..kwh" * bs.weight) AS "electricity.total.energy_consumption..kwh__upgrade", sum((coalesce(bs."out.electricity.total.energy_consumption..kwh", 0) - coalesce(up."out.electricity.total.energy_consumption..kwh", 0)) * bs.weight) AS "electricity.total.energy_consumption..kwh__savings", approx_percentile(bs."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption..kwh__baseline__quartiles", approx_percentile(bs."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE bs."out.electricity.total.energy_consumption..kwh" != 0) AS "electricity.total.energy_consumption..kwh__baseline__nonzero_quartiles", approx_percentile(up."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption..kwh__upgrade__quartiles", approx_percentile(up."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE up."out.electricity.total.energy_consumption..kwh" != 0) AS "electricity.total.energy_consumption..kwh__upgrade__nonzero_quartiles", approx_percentile(coalesce(bs."out.electricity.total.energy_consumption..kwh", 0) - coalesce(up."out.electricity.total.energy_consumption..kwh", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption..kwh__savings__quartiles", approx_percentile(coalesce(bs."out.electricity.total.energy_consumption..kwh", 0) - coalesce(up."out.electricity.total.energy_consumption..kwh", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE coalesce(bs."out.electricity.total.energy_consumption..kwh", 0) - coalesce(up."out.electricity.total.energy_consumption..kwh", 0) != 0) AS "electricity.total.energy_consumption..kwh__savings__nonzero_quartiles" FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS up ON bs.bldg_id = up.bldg_id AND bs."in.nhgis_tract_gisjoin" = up."in.nhgis_tract_gisjoin" AND bs.state = up.state AND bs.upgrade = 0 AND up.upgrade = 1 AND up.applicability = true WHERE bs.applicability = true AND bs.upgrade = 0 AND bs.state = 'CO' GROUP BY 1 ORDER BY 1